text:
& when (@listing-grid-item-actions__position = absolute) {
    .listing-grid-item-actions-absolute();

    & when (@critical) {
        @media @media-hover-none {
            .product-item-details {
                .product-item-actions {
                    opacity: 1;
                    pointer-events: all;
                    .lib-css(transform, @listing-grid-item-actions__absolute__visible__transform);
                }
            }
        }
    }

    & when not (@critical) {
        @media @media-hover {
            &:hover,
            &:has(:focus-visible) {
                .product-item-details {
                    .product-item-actions {
                        opacity: 1;
                        pointer-events: all;
                        .lib-css(transform, @listing-grid-item-actions__absolute__visible__transform);
                    }
                }
            }
        }
    }
}

& when (@critical) {
    // enable for both hover and hover-none devices
    & when not (@_hover-none-visible-height = false) {
        .listing-reveal-on-hover-base(@_aspect-ratio);
    }

    @media @media-hover {
        // enable for hover devices only
        & when (@_hover-none-visible-height = false) {
            .listing-reveal-on-hover-base(@_aspect-ratio);
        }
        .listing-reveal-on-hover-visible-height(@_aspect-ratio, @_visible-height);
    }

    // enable for hover-none devices
    @media @media-hover-none {
        & when (@listing-grid-item-actions-secondary__position = absolute) {
            .product-item-inner,
            .actions-secondary {
                opacity: 1;
                pointer-events: all;
            }
        }
        & when not (@_hover-none-visible-height = false) {
            .actions-primary {
                opacity: 0;
                pointer-events: none;
            }
            .listing-reveal-on-hover-visible-height(@_aspect-ratio, @_hover-none-visible-height);
        }
    }
}

@media (-moz-touch-enabled), (pointer: coarse) {
    .ui.dropdown .scrollhint.menu:not(.hidden)::before {
        animation: scrollhint @scrollhintDuration @scrollhintEasing @scrollhintIteration;
        content: "";
        z-index: @scrollhintZIndex;
        display: block;
        position: absolute;
        opacity: 0;
        right: @scrollhintOffsetRight;
        top: 0;
        height: 100%;
        border-right: @scrollhintRightBorder;
        border-left: @scrollhintLeftBorder;
        border-image: linear-gradient(to bottom, @scrollhintStartColor, @scrollhintEndColor) 1 100%;
    }

    .ui.inverted.dropdown .scrollhint.menu:not(.hidden)::before {
        border-image: linear-gradient(to bottom, @invertedScrollhintStartColor, @invertedScrollhintEndColor) 1 100%;
    }

    @keyframes scrollhint {
        0% {
            opacity: 1;
            top: 100%;
        }
        100% {
            opacity: 0;
            top: 0;
        }
    }
}

& when (@variationSidebarRight) {
    & when (@variationSidebarThin) {
        .ui.visible.thin.right.sidebar ~ .fixed,
        .ui.visible.thin.right.sidebar ~ .pusher {
            transform: translate3d(-@thinWidth, 0, 0);
        }

        & when (@variationSidebarVeryThin) {
            .ui.visible[class*="very thin"].right.sidebar ~ .fixed,
            .ui.visible[class*="very thin"].right.sidebar ~ .pusher {
                transform: translate3d(-@veryThinWidth, 0, 0);
            }
        }
    }

    & when (@variationSidebarWide) {
        .ui.visible.wide.right.sidebar ~ .fixed,
        .ui.visible.wide.right.sidebar ~ .pusher {
            transform: translate3d(-@wideWidth, 0, 0);
        }

        & when (@variationSidebarVeryWide) {
            .ui.visible[class*="very wide"].right.sidebar ~ .fixed,
            .ui.visible[class*="very wide"].right.sidebar ~ .pusher {
                transform: translate3d(-@veryWideWidth, 0, 0);
            }
        }
    }
}

& when (@variationSidebarLeft) {
    & when (@variationSidebarThin) {
        .ui.visible.thin.left.sidebar ~ .fixed,
        .ui.visible.thin.left.sidebar ~ .pusher {
            transform: translate3d(@thinWidth, 0, 0);
        }

        & when (@variationSidebarVeryThin) {
            .ui.visible[class*="very thin"].left.sidebar ~ .fixed,
            .ui.visible[class*="very thin"].left.sidebar ~ .pusher {
                transform: translate3d(@veryThinWidth, 0, 0);
            }
        }
    }

    & when (@variationSidebarWide) {
        .ui.visible.wide.left.sidebar ~ .fixed,
        .ui.visible.wide.left.sidebar ~ .pusher {
            transform: translate3d(@wideWidth, 0, 0);
        }

        & when (@variationSidebarVeryWide) {
            .ui.visible[class*="very wide"].left.sidebar ~ .fixed,
            .ui.visible[class*="very wide"].left.sidebar ~ .pusher {
                transform: translate3d(@veryWideWidth, 0, 0);
            }
        }
    }
}

& when (@variationButtonSpaced) {
    .ui.spaced.buttons .ui.button {
        margin-bottom: @spacedMargin;
        margin-right: @spacedMargin;
        border-radius: @basicBorderRadius;
    }
    & when (@variationButtonBasic) {
        .ui.spaced.basic.buttons {
            border: none;
            & .button {
                border: @basicGroupBorder;
                &.basic {
                    border: none;
                }
            }
        }
        & when (@variationButtonVertical) {
            .ui.spaced.basic.vertical.buttons .button:first-child {
                border-top: @basicGroupBorder;
            }
        }
        & when (@variationButtonWrapping) {
            .ui.spaced.basic.wrapping.buttons .button@{notBasic} {
                border-top: @basicGroupBorder;
                border-right: @basicGroupBorder;
                &:first-child {
                    border-left: @basicGroupBorder;
                }
            }
        }
        & when (@variationButtonInverted) {
            .ui.spaced.basic.inverted.buttons .basic.button {
                margin-bottom: e(%("calc(%d + %d)", @spacedMargin, @basicColoredBorderSize));
                margin-top: @basicColoredBorderSize;
            }
        }
    }
}

&:hover,
  &:focus {
    & when (@border = transparent) {
      & when (@theme = dark) {
        .button-color(colorPalette('@{color}', 7); null; transparent);
      }
      & when (not (@theme = dark) and not (@theme = variable)) {
        .button-color(colorPalette('@{color}', 5); null; transparent);
      }
      & when (@theme = variable) {
        .button-color(@borderActive; transparent; transparent);
      }
    }
    & when not (@border = transparent) {
      & when (@theme = dark) {
        .button-color(
          colorPalette('@{color}', 7); null; colorPalette('@{color}', 7)
        );
      }
      & when (not (@theme = dark) and not (@theme = variable)) {
        .button-color(
          colorPalette('@{color}', 5); null; colorPalette('@{color}', 5)
        );
      }
      & when (@theme = variable) {
        .button-color(@borderHover; transparent; @borderHover);
      }
    }
  }

&.btn-material {
    background-color: transparent!important;
    border: none!important;
    .border-radius(2px);

    > button {
        .btn-material;
    }

    button.ui-button.ui-splitbutton-menubutton  {
        border: none;
        .btn-interactions(@btn-background-color);
    }

    &.btn-default > button {
        .btn-interactions(@btn-background-color);
        color: rgba(0,0,0,.87)!important;
        span.ui-icon {
            color: rgba(0,0,0,.87);
        }
    }

    &.btn-success > button {
        .btn-interactions(@btn-background-color);
        color: @green!important;
        span.ui-icon {
            color: green;
        }
    }

    &.btn-primary > button {
        .btn-interactions(@btn-background-color);
        color: @light-blue!important;
        span.ui-icon {
            color: @light-blue;
        }
    }

    &.btn-teal > button {
      .btn-interactions(@btn-background-color);
      color: @admin-teal !important;

      span.ui-icon {
        color: @admin-teal;
      }

    }
}

& when (@variationButtonBasic) {
    .ui.spaced.basic.buttons {
        border: none;
        & .button {
            border: @basicGroupBorder;
            &.basic {
                border: none;
            }
        }
    }
    & when (@variationButtonVertical) {
        .ui.spaced.basic.vertical.buttons .button:first-child {
            border-top: @basicGroupBorder;
        }
    }
    & when (@variationButtonWrapping) {
        .ui.spaced.basic.wrapping.buttons .button@{notBasic} {
            border-top: @basicGroupBorder;
            border-right: @basicGroupBorder;
            &:first-child {
                border-left: @basicGroupBorder;
            }
        }
    }
    & when (@variationButtonInverted) {
        .ui.spaced.basic.inverted.buttons .basic.button {
            margin-bottom: e(%("calc(%d + %d)", @spacedMargin, @basicColoredBorderSize));
            margin-top: @basicColoredBorderSize;
        }
    }
}

& .step {
    background: @circularStepColor;
    cursor: default;
    height: @circularStepBorderWidth;
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    flex: 1;
    position: relative;
    margin-left: @circularStepRingSize;

    &::before {
        left: -@circularStepRingSize;
    }
    &::after {
        left: @circularStepIconDistance;
    }

    &.completed {
        background: @circularStepCompletedBackground;
    }
    &.completed::after {
        left: @circularStepCompletedIconDistance;
    }
    &:last-child {
        flex: 0;
    }
    & .content {
        margin-top: @circularStepContentMarginTop;
        padding: @circularStepContentPadding;
        &.center.aligned {
            margin-top: @circularStepContentCenterAlignedMarginTop;
            & .title {
                padding: @circularStepContentPadding;
                margin-left: @circularStepContentCenterAlignedMarginLeft;
                background: @circularStepContentCenterAlignedBackground;
            }
        }
        &.bottom.aligned {
            margin-top: @circularStepContentBottomAlignedMarginTop;
        }
        &:not(.aligned) .title + .description {
            margin-top: @circularStepContentDescriptionDistance;
        }
    }
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.stackable.menu {
        flex-direction: column;

        &.pointing .active.item::after when (@variationMenuPointing) {
            display: none;
        }
    }
    .ui.stackable.menu .item {
        width: 100% !important;
    }
    .ui.stackable.menu .item::before {
        position: absolute;
        content: "";
        top: auto;
        bottom: 0;
        left: 0;
        width: 100%;
        height: @dividerSize;
        background: @verticalDividerBackground;
    }

    .ui.stackable.menu .left.menu,
    .ui.stackable.menu .left.item {
        margin-right: 0 !important;
    }
    .ui.stackable.menu .right.menu,
    .ui.stackable.menu .right.item {
        margin-left: 0 !important;
    }
    .ui.stackable.menu .center.menu,
    .ui.stackable.menu .center.item {
        margin-left: 0 !important;
        margin-right: 0 !important;
    }

    .ui.stackable.menu .right.menu,
    .ui.stackable.menu .center.menu,
    .ui.stackable.menu .left.menu {
        flex-direction: column;
    }
}

& when (@variationModalBasic) {
    .ui.basic.modal {
        background-color: transparent;
        border: none;
        border-radius: 0;
        box-shadow: none !important;
        color: @basicModalColor;
    }
    .ui.ui.modal > .basic.header,
    .ui.ui.modal > .basic.actions,
    .ui.basic.modal > .header,
    .ui.basic.modal > .content,
    .ui.basic.modal > .actions {
        background-color: transparent;
    }
    .ui.modal > .basic.header {
        border-bottom: none;
    }
    .ui.basic.modal > .header {
        color: @basicModalHeaderColor;
        border-bottom: none;
    }
    & when (@variationModalClose) {
        .ui.basic.modal > .close {
            top: @basicModalCloseTop;
            right: @basicModalCloseRight;
            color: @basicInnerCloseColor;
        }
    }
    .ui.inverted.dimmer > .basic.modal {
        color: @basicInvertedModalColor;
    }
    .ui.inverted.dimmer > .ui.basic.modal > .header {
        color: @basicInvertedModalHeaderColor;
    }
}

&-panel{
    &-icon-btn{
        display: inline-block;
        width: 20px;
        height: 24px;
        line-height: 26px;
        margin-top: 4px;
        text-align: center;
        cursor: pointer;
        color: @btn-disable-color;
        transition: color @transition-time @ease-in-out;
        &:hover{
            color: @primary-color;
        }
        i{
            font-size: 14px;
        }
    }

    &-body-wrapper&-with-sidebar{
        padding-left: 92px;
    }
    &-sidebar{
        width: 92px;
        float: left;
        margin-left: -92px;
        position: absolute;
        top: 0;
        bottom: 0;
        background: @table-thead-bg;
        border-right: 1px solid @border-color-split;
        border-radius: @border-radius-small 0 0 @border-radius-small;
        overflow: auto;
    }
    &-shortcut{
        padding: @btn-padding-large;
        transition: all @transition-time @ease-in-out;
        cursor: pointer;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;

        &:hover{
            background: @border-color-split;
        }
    }
    &-body{
        float: left;
    }
}

&-list{
    margin-top: 8px;

    &-file{
        padding: 4px;
        color: @text-color;
        border-radius: @border-radius-small;
        transition: background-color @transition-time @ease-in-out;
        overflow: hidden;
        position: relative;

        & > span{
            cursor: pointer;
            transition: color @transition-time @ease-in-out;
            i{
                display: inline-block;
                width: @font-size-small;
                height: @font-size-small;
                color: @text-color;
                text-align: center;
            }
        }

        &:hover{
            background: @input-disabled-bg;
            & > span{
                color: @primary-color;
                i{
                    color: @text-color;
                }
            }
            .@{upload-prefix-cls}-list-remove{
                opacity: 1;
            }
        }
    }
    &-remove{
        opacity: 0;
        font-size: 18px;
        cursor: pointer;
        float: right;
        margin-right: 4px;
        color: @legend-color;
        transition: all @transition-time ease;
        &:hover{
            color: #444;
        }
    }
}

&-filter{
    display: inline-block;
    cursor: pointer;
    position: relative;
    //top: 1px;

    i{
        color: @btn-disable-color;
        transition: color @transition-time @ease-in-out;
        &:hover{
            color: inherit;
        }
        &.on{
            color: @primary-color;
        }
    }
    &-list{
        padding: 8px 0 0;
        &-item{
            padding: 0 12px 8px;

            .ivu-checkbox-wrapper + .ivu-checkbox-wrapper{
                margin: 0;
            }
            label {
                display: block;

                & > span{
                    margin-right: 4px;
                }
            }
        }
        ul{
            padding-bottom: 8px;
        }
        .select-item(@table-prefix-cls, @table-select-item-prefix-cls);
    }
    &-footer{
        padding: 4px;
        border-top: 1px solid @border-color-split;
        overflow: hidden;
        button:first-child{
            float: left;
        }
        button:last-child{
            float: right;
        }
    }
}

&-status {
    line-height: inherit;
    vertical-align: baseline;

    &-dot {
        width: 6px;
        height: 6px;
        display: inline-block;
        border-radius: 50%;
        vertical-align: middle;
        position: relative;
        top: -1px;
    }
    &-success {
        background-color: @success-color;
    }
    &-processing {
        background-color: @processing-color;
        position: relative;
        &:after {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            border-radius: 50%;
            border: 1px solid @processing-color;
            content: '';
            animation: aniStatusProcessing 1.2s infinite ease-in-out;
        }
    }
    &-default {
        background-color: @normal-color;
    }
    &-error {
        background-color: @error-color;
    }
    &-warning {
        background-color: @warning-color;
    }
    &-text {
        display: inline-block;
        color: @text-color;
        font-size: @font-size-small;
        margin-left: 6px;
    }
}

&-item {
    display: inline-block;
    //float: left;
    vertical-align: middle;
    min-width: @btn-circle-size;
    height: @btn-circle-size;
    line-height: @btn-circle-size - 2px;
    margin-right: 4px;
    text-align: center;
    list-style: none;
    background-color: #fff;
    user-select: none;
    cursor: pointer;
    font-family: Arial;
    font-weight: 500;
    border: 1px solid @border-color-base;
    border-radius: @btn-border-radius;
    //transition: all @transition-time @ease-in-out;
    transition: border @transition-time @ease-in-out, color @transition-time @ease-in-out;

    a {
        font-family: "Monospaced Number";
        margin: 0 6px;
        text-decoration: none;
        color: @text-color;
        //transition: none;
    }

    &:hover {
        border-color: @primary-color;
        a {
            color: @primary-color;
        }
    }

    &-active {
        border-color: @primary-color;

        a, &:hover a {
            color: @primary-color;
        }
    }
}

&-search{
    cursor: pointer;
    padding: 0 16px !important;
    background: @primary-color !important;
    color: #fff !important;
    border-color: @primary-color !important;
    transition: all @transition-time @ease-in-out;
    position: relative;
    z-index: 2;

    i{
        font-size: 16px;
    }

    &:hover{
        background: tint(@primary-color, 20%) !important;
        border-color: tint(@primary-color, 20%) !important;
    }
    &:active{
        background: shade(@primary-color, 5%) !important;
        border-color: shade(@primary-color, 5%) !important;
    }

    &-icon{
        cursor: pointer;
        transition: color @transition-time @ease-in-out;
        &:hover{
            color: inherit;
        }
    }

    &:before{
        content: '';
        display: block;
        width: 1px;
        position: absolute;
        top: -1px;
        bottom: -1px;
        left: -1px;
        background: inherit;
    }
}

@media only screen and (max-width: 767.98px) {
  .ui.stackable.grid .ui.vertical.divider,
  .ui.grid .stackable.row .ui.vertical.divider {
    display: table;
    white-space: nowrap;
    height: auto;
    margin: '';
    overflow: hidden;
    line-height: 1;
    text-align: center;
    position: static;
    top: 0;
    left: 0;
    -webkit-transform: none;
            transform: none;
  }
  .ui.stackable.grid .ui.vertical.divider::before,
  .ui.grid .stackable.row .ui.vertical.divider::before,
  .ui.stackable.grid .ui.vertical.divider::after,
  .ui.grid .stackable.row .ui.vertical.divider::after {
    left: 0;
    border-left: none;
    border-right: none;
    content: '';
    display: table-cell;
    position: relative;
    top: 50%;
    width: 50%;
    background-repeat: no-repeat;
  }
  .ui.stackable.grid .ui.vertical.divider::before,
  .ui.grid .stackable.row .ui.vertical.divider::before {
    background-position: right 1em top 50%;
  }
  .ui.stackable.grid .ui.vertical.divider::after,
  .ui.grid .stackable.row .ui.vertical.divider::after {
    background-position: left 1em top 50%;
  }
}

&-bordered {
  .@{descriptions-prefix-cls}-view {
    border: 1px solid @border-color-split;

    > table {
      table-layout: auto;
      border-collapse: collapse;
    }
  }

  .@{descriptions-prefix-cls}-item-label,
  .@{descriptions-prefix-cls}-item-content {
    padding: @descriptions-default-padding;
    border-right: 1px solid @border-color-split;

    &:last-child {
      border-right: none;
    }
  }

  .@{descriptions-prefix-cls}-item-label {
    background-color: @descriptions-bg;

    &::after {
      display: none;
    }
  }

  .@{descriptions-prefix-cls}-row {
    border-bottom: 1px solid @border-color-split;

    &:last-child {
      border-bottom: none;
    }
  }

  &.@{descriptions-prefix-cls}-middle {
    .@{descriptions-prefix-cls}-item-label,
    .@{descriptions-prefix-cls}-item-content {
      padding: @descriptions-middle-padding;
    }
  }

  &.@{descriptions-prefix-cls}-small {
    .@{descriptions-prefix-cls}-item-label,
    .@{descriptions-prefix-cls}-item-content {
      padding: @descriptions-small-padding;
    }
  }
}

&-vertical,
  &-vertical-left,
  &-vertical-right,
  &-inline {
    .@{menu-prefix-cls}-item {
      position: relative;

      &::after {
        position: absolute;
        top: 0;
        right: 0;
        bottom: 0;
        border-right: @menu-item-active-border-width solid @menu-highlight-color;
        transform: scaleY(0.0001);
        opacity: 0;
        transition: transform @menu-animation-duration-normal @ease-out,
          opacity @menu-animation-duration-normal @ease-out;
        content: '';
      }
    }

    .@{menu-prefix-cls}-item,
    .@{menu-prefix-cls}-submenu-title {
      height: @menu-item-height;
      margin-top: @menu-item-vertical-margin;
      margin-bottom: @menu-item-vertical-margin;
      padding: 0 16px;
      overflow: hidden;
      line-height: @menu-item-height;
      text-overflow: ellipsis;
    }

    // disable margin collapsed
    .@{menu-prefix-cls}-submenu {
      padding-bottom: 0.02px;
    }

    .@{menu-prefix-cls}-item:not(:last-child) {
      margin-bottom: @menu-item-boundary-margin;
    }

    > .@{menu-prefix-cls}-item,
    > .@{menu-prefix-cls}-submenu > .@{menu-prefix-cls}-submenu-title {
      height: @menu-inline-toplevel-item-height;
      line-height: @menu-inline-toplevel-item-height;
    }
  }

&-item {
  position: relative;
  display: block;
  min-width: 100px;
  padding: 5px @control-padding-horizontal;
  overflow: hidden;
  color: @text-color;
  font-weight: normal;
  line-height: @line-height-base;
  white-space: nowrap;
  text-overflow: ellipsis;
  cursor: pointer;
  transition: background 0.3s ease;

  &:hover {
    background-color: @item-hover-bg;
  }

  &:first-child {
    border-radius: @border-radius-base @border-radius-base 0 0;
  }

  &:last-child {
    border-radius: 0 0 @border-radius-base @border-radius-base;
  }

  &-disabled {
    color: @disabled-color;
    cursor: not-allowed;

    &:hover {
      color: @disabled-color;
      background-color: @mentions-dropdown-menu-item-hover-bg;
      cursor: not-allowed;
    }
  }

  &-selected {
    color: @text-color;
    font-weight: @select-item-selected-font-weight;
    background-color: @background-color-light;
  }

  &-active {
    background-color: @item-hover-bg;
  }
}

&-head {
  min-height: @card-head-height;
  margin-bottom: -1px; // Fix card grid overflow bug: https://gw.alipayobjects.com/zos/rmsportal/XonYxBikwpgbqIQBeuhk.png
  padding: 0 @card-padding-base;
  color: @card-head-color;
  font-weight: 500;
  font-size: @card-head-font-size;
  background: @card-head-background;
  border-bottom: @border-width-base @border-style-base @border-color-split;
  border-radius: @card-radius @card-radius 0 0;
  .clearfix();

  &-wrapper {
    display: flex;
    align-items: center;
