          height: 1px;
          background: @line-deep-color;
          display: block;
          position: absolute;
          left: 60px;
          top: 30px;
        }
        & .arrow {
          width: 10px;
          height: 10px;
          display: block;
          position: absolute;
          right: 60px;
          top: 26px;
          border-right: solid;
          border-top: solid;
          border-width: 1px;
          border-color: @line-deep-color;
          transform: rotate(45deg);
        }
      }
    }
  }
}
